mapper.select:
SELECT product_id, seller_id, name, description, category, price, stock_qty, thumbnail_url, expiration_date, created_at, updated_at
FROM products
WHERE product_id = #{productId}

mapper.update:
UPDATE products
SET name = #{name},
    description = #{description},
    category = #{category},
    price = #{price},
    stock_qty = #{stockQty},
    thumbnail_url = #{thumbnailUrl},
    expiration_date = #{expirationDate}
WHERE product_id = #{productId}
  AND seller_id = #{sellerId}

mapper.delete:
DELETE FROM products
WHERE product_id = #{productId}
  AND seller_id = #{sellerId}

mapper.update:
UPDATE products
SET stock_qty = stock_qty - #{quantity}
WHERE product_id = #{productId}
  AND stock_qty >= #{quantity}
